Teniendo en cuenta las definiciones puestas a continuación, seleccione cuál de las siguientes asignaciones en ADA son correctas.
type Weight is digits 4 range 0.0 .. 200.0; 
type Height is digits 4 range 0.0 .. 200.0; 
w0, w1: Weight; 
h0, h1: Height;

r.o:
w0 := 75.4; 
h0 := 180.0; 
h1 := w0 + 100.0;  (No, w0 es distinto tipo que h1)

w0 := 75.4; 
h0 := 180.0; 
h1 := w0 + h0/10.0;  (No, w0 es distinto tipo que h1)

w0 := 75.4; 
h0 := 180.0; 
h1 := h0 + 52.0;  (No, la suma se sale del rango)

float f (float x); // Function f(x). Externally defined
float df (float x); // Derivative of f(x). Externally defined
float fabs (float x); // Absolute value of x. Externally defined

float x = 0.0, xnew, xold;
float error = 0.001;

int main() {
    xnew = xold = x;

    for (i = 0; i < 1000; i++) {
        xnew = xold + f(xold)/df(xold);

        if (fabs(xnew - xold) < error) break;
    }

    x = xnew;

    printf("%f\n", x);

    return 0;
}

float f (float x); // Function f(x). Externally defined
float df (float x); // Derivative of f(x). Externally defined
float fabs (float x); // Absolute value of x. Externally defined

float x = 0.0, xnew, xold;
float error = 0.001;

int main() {
    xold = xnew = x;

    iteration: xnew = xold + f(xold)/df(xold);

    if (fabs(xnew - xold) > error)
        goto iteration;

    x = xnew;

    printf("%f\n", x);

    return 0;
}

float f (float x); // Function f(x). Externally defined
float df (float x); // Derivative of f(x). Externally defined
float fabs (float x); // Absolute value of x. Externally defined

float x = 0.0, xnew, xold;
float error = 0.001;

int main() {
    xold = x;
    xnew = xold + 2*error;

    while (fabs(xnew - xold) < error) {
        xnew = xold + f(xold)/df(xold);
    }

    x = xnew;

    printf("%f\n", x);

    return 0;
}

float f (float x); // Function f(x). Externally defined
float df (float x); // Derivative of f(x). Externally defined
float fabs (float x); // Absolute value of x. Externally defined

float x = 0.0, xnew, xold;
float error = 0.001;

int main() {
    xold = xnew = x;

    do {
        xnew = xold + f(xold)/df(xold);
    } while (fabs(xnew - xold) > error);

    x = xnew;

    printf("%f\n", x);

    return 0;
}

float max (int v0, char v1);

int main() {
    int a = 1;
    char b = 2;

    float c;

    c = max(a, b);

    return 0;
}

float transf(int v0);
float transf(char v1);

int main() {
    int a = 1, b = 2;

    float c;

    c = transf(a) + transf(b);

    printf("%f\n", c);

    return 0;
}

int equal (int a, char b) {

    if (a == b)

        return 1;

    else

        return 0;

}

int main() {

    int a = 1;

    char b = 1;

    float c;

    c = (float) (a + (int)b);

    if (c == 2.0)

        printf("Ok!");

    else

        printf("Error!");

    return 0;

}

#include <stdio.h>

int main() {
    float a = 1.9;
    int b;

    b = (int) (a + 0.5);

    if (b == 2)
        printf("Ok!");
    else
        printf("Error!");

    return 0;
}

#include <stdio.h>

